306	func runPreCloseReviewGroup(ctx context.Context, reviewer BeadReviewer, beadID, resultRev string, impl ImplementerRouting) (*ReviewGroupResult, error) {
307		if reviewer == nil {
308			return nil, fmt.Errorf("review-group: reviewer required")
309		}
310		if groupReviewer, ok := reviewer.(reviewGroupReviewer); ok {
311			return groupReviewer.ReviewGroup(ctx, beadID, resultRev, impl)
312		}
313		result, err := reviewer.ReviewBead(ctx, beadID, resultRev, impl)
314		group := &ReviewGroupResult{
315			BeadID:    beadID,
316			ResultRev: resultRev,
317			Slots: []ReviewGroupSlotResult{
318				{
319					ReviewerIndex: 0,
320					Result:        result,
321				},
322			},
323		}
324		if err != nil {
325			group.Slots[0].Error = err.Error()
326		}
327		return group, err
328	}
329	
330	func reducePreCloseReviewGroup(group *ReviewGroupResult) (*ReviewResult, error) {
331		if group == nil || len(group.Slots) == 0 {
332			return nil, fmt.Errorf("review-group: no review slots")
333		}
334		var firstApprove *ReviewResult
335		var firstNonApprove *ReviewResult
336		var firstResult *ReviewResult
337		for _, slot := range group.Slots {
338			if slot.Result != nil && firstResult == nil {
339				firstResult = slot.Result
340			}
341			if slot.Error != "" && slot.Result == nil {
342				if firstResult != nil {
343					return firstResult, fmt.Errorf("review-group slot %d: %s", slot.ReviewerIndex, slot.Error)
344				}
345				return nil, fmt.Errorf("review-group slot %d: %s", slot.ReviewerIndex, slot.Error)
346			}
347			if slot.Result == nil {
348				if firstResult != nil {
349					return firstResult, fmt.Errorf("review-group slot %d: missing review result", slot.ReviewerIndex)
350				}
351				return nil, fmt.Errorf("review-group slot %d: missing review result", slot.ReviewerIndex)
352			}
353			res := slot.Result
354			switch res.Verdict {
355			case VerdictApprove:
356				if !reviewResultHasACEvidence(res) {
357					return res, fmt.Errorf("%w: approve verdict without per-AC evidence", ErrReviewVerdictUnparseable)
358				}
359				if firstApprove == nil {
360					firstApprove = res
361				}
362			case VerdictRequestChanges, VerdictBlock:
363				if firstNonApprove == nil {
364					firstNonApprove = res
365				}
366			default:
367				if firstNonApprove == nil {
368					firstNonApprove = res
369				}
370			}
371		}
372		if firstNonApprove != nil {
373			return firstNonApprove, nil
374		}
375		return firstApprove, nil
376	}
377	
378	func reviewResultHasACEvidence(res *ReviewResult) bool {
379		if res == nil || res.Verdict != VerdictApprove {
380			return false
381		}
382		if len(res.PerAC) == 0 {
383			return false
384		}
385		for _, ac := range res.PerAC {
386			if strings.TrimSpace(ac.Evidence) == "" {
387				return false
388			}
389		}
390		return true
391	}
