1256					if isNoViableProviderReport(report) {
1257						report.OutcomeReason = FailureModeNoViableProvider
1258						retryAfter := now().UTC().Add(CapLoopCooldown(ProviderUnavailableCooldown))
1259						if err := w.Store.SetExecutionCooldown(candidate.ID, retryAfter, report.Status, report.Detail); err != nil {
1260							_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
1261								return commitOutcomeError("SetExecutionCooldown", assignee, result, err)
1262							})
1263							if ctx.Err() != nil {
1264								return result, ctx.Err()
1265							}
1266							continue
1267						}
1268						report.RetryAfter = retryAfter.Format(time.RFC3339)
1269					} else {
1270						report = w.runPostAttemptTriage(ctx, candidate, report, runtime, assignee, now)
1271						if shouldSuppressNoProgress(report) {
1272							retryAfter := now().UTC().Add(CapLoopCooldown(noProgressCooldown))
1273							if err := w.Store.SetExecutionCooldown(candidate.ID, retryAfter, report.Status, report.Detail); err != nil {
1274								_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
1275									return commitOutcomeError("SetExecutionCooldown", assignee, result, err)
1276								})
1277								if ctx.Err() != nil {
1278									return result, ctx.Err()
1279								}
1280								continue
1281							}
1282							report.RetryAfter = retryAfter.Format(time.RFC3339)
1283						}
1284					}
1285					result.Failures++
1286					result.LastFailureStatus = report.Status
1287				}
1288			}
1289	
1290			result.Results = append(result.Results, report)
1291	
1292			// Skip the late execute-bead append for already-satisfied beads —
1293			// the satisfied path appends its own terminal event before
1294			// CloseWithEvidence so the closure gate sees execution evidence.
1295			// Duplicating it here would yield two identical events.
1296			if report.Status != ExecuteBeadStatusAlreadySatisfied {
1297				if err := w.Store.AppendEvent(candidate.ID, executeBeadLoopEvent(report, assignee, now().UTC())); err != nil {
1298					_ = commitOutcome(ctx, w.Store, candidate.ID, func() error {
1299						return commitOutcomeError("AppendEvent", assignee, result, err)
1300					})
1301					// Event recording failure is non-terminal: log it and continue.
1302					// result counters were already updated by the outcome block above;
1303					// do not double-count by re-running the outcome handler.
1304					if runtime.Log != nil {
1305						_, _ = fmt.Fprintf(runtime.Log, "outcome store error (AppendEvent %s): %v (continuing)\n", candidate.ID, err)
1306					}
1307					if ctx.Err() == nil {
1308						_ = w.Store.SetExecutionCooldown(candidate.ID, now().UTC().Add(StoreErrorCooldown), "loop-error", "AppendEvent: "+err.Error())
1309					}
1310					if ctx.Err() != nil {
1311						return result, ctx.Err()
1312					}
1313					continue
1314				}
1315			}
1316	
1317			// Emit terminal progress phase event.
1318			terminalPhase := "failed"
1319			if report.Status == ExecuteBeadStatusSuccess || report.Status == ExecuteBeadStatusAlreadySatisfied {
1320				terminalPhase = "done"
1321			} else if report.PreserveRef != "" {
1322				terminalPhase = "preserved"
1323			}
1324			// Use the real attempt_id from the report if available.
1325			finalAttemptID := report.AttemptID
1326			if finalAttemptID == "" {
1327				finalAttemptID = provAttemptID
1328			}
1329			phaseSeq++
1330			emitProgress(runtime.ProgressCh, ProgressEvent{
1331				EventID:   "evt-" + randomProgressID(),
1332				AttemptID: finalAttemptID,
1333				WorkerID:  runtime.WorkerID,
1334				ProjectID: runtime.ProjectRoot,
1335				BeadID:    candidate.ID,
1336				Harness:   harness,
1337				Model:     model,
1338				Profile:   profile,
1339				Phase:     terminalPhase,
1340				PhaseSeq:  phaseSeq,
1341				Heartbeat: false,
1342				TS:        now().UTC(),
1343				ElapsedMS: now().Sub(runStart).Milliseconds(),
1344				Message:   report.Detail,
1345			})
1346	
1347			emit("bead.result", map[string]any{
1348				"bead_id":              candidate.ID,
1349				"status":               report.Status,
1350				"detail":               report.Detail,
1351				"session_id":           report.SessionID,
1352				"result_rev":           report.ResultRev,
1353				"base_rev":             report.BaseRev,
1354				"preserve_ref":         report.PreserveRef,
1355				"no_changes_rationale": report.NoChangesRationale,
1356				"duration_ms":          now().Sub(runStart).Milliseconds(),
1357			})
1358	
1359			if runtime.Log != nil {
1360				_, _ = fmt.Fprintf(runtime.Log, "✓ %s → %s\n", candidate.ID, formatLoopResult(report))
1361			}
1362	
1363			if runtime.Once {
1364				applyStop(work.StopInput{Once: true})
1365				return result, nil
1366			}
1367		}
1368	}
