1370	// emitPickerPrioritySkips fires a picker.priority_skip event when the picker
1371	// chose `chosen` while at least one strictly higher-priority bead was passed
1372	// over (ddx-9d55601f AC #4). Skips at the same priority as `chosen` are NOT
1373	// reported — those are FIFO order or label-filter siblings, not starvation.
1374	//
1375	// The emit is guarded so it costs nothing when the chosen bead is the highest-
1376	// priority bead the picker saw (the common case).
1377	func emitPickerPrioritySkips(emit func(string, map[string]any), chosen bead.Bead, skips []pickerSkip) {
1378		if len(skips) == 0 {
1379			return
1380		}
1381		var higher []map[string]any
1382		for _, s := range skips {
1383			if s.Priority < chosen.Priority {
1384				higher = append(higher, map[string]any{
1385					"bead_id":    s.BeadID,
1386					"priority":   s.Priority,
1387					"queue_rank": queueRankValue(s.BeadRank),
1388					"reason":     s.Reason,
1389				})
1390			}
1391		}
1392		if len(higher) == 0 {
1393			return
1394		}
1395		emit("picker.priority_skip", map[string]any{
1396			"chosen_bead_id":  chosen.ID,
1397			"chosen_priority": chosen.Priority,
1398			"skipped":         higher,
1399		})
1400	}
1401	
1402	// pickerSkip records a single bead that the picker passed over while looking
1403	// for the next candidate. It is used to emit a structured picker.priority_skip
1404	// event when a worker claims a lower-priority bead while a higher-priority
1405	// bead was skipped, so future starvation regressions are observable.
1406	//
1407	// Reason values are bounded to the set named in ddx-9d55601f AC #4:
1408	//
1409	//	label_filter, in_attempted, claim_race, eligibility_filter, retry_cooldown
1410	//
1411	// Note: eligibility_filter and retry_cooldown are applied upstream in
1412	// Store.ReadyExecution (so beads filtered for those reasons never reach
1413	// nextCandidate at all). They are part of the reason vocabulary so future
1414	// picker rearrangements can re-emit them without changing the schema.
1415	type pickerSkip struct {
1416		BeadID   string
1417		Priority int
1418		BeadRank *int
1419		Reason   string
1420	}
1421	
1422	func hasGuardSkips(skips []pickerSkip) bool {
1423		for _, skip := range skips {
1424			switch skip.Reason {
1425			case "label_filter", "in_attempted", "claim_race", "eligibility_filter", "retry_cooldown", "target_bead":
1426				continue
1427			default:
1428				return true
1429			}
1430		}
1431		return false
1432	}
1433	
1434	func queueRankValue(raw any) any {
1435		rank, ok := parseQueueRank(raw)
1436		if !ok {
1437			return nil
1438		}
1439		return rank
1440	}
1441	
1442	// nextCandidate returns the next claimable bead from the execution-ready
1443	// queue along with the list of higher-priority beads it skipped (and the
1444	// reason for each skip). The returned skips slice is only meaningful when
1445	// ok=true: it contains every entry that came BEFORE the chosen candidate
1446	// in the priority-sorted ReadyExecution result.
1447	//
1448	// It delegates filter+sort to PreviewQueue and then additionally filters out
1449	// beads already present in the current drain results slice (which is
1450	// non-deterministic across runs and therefore excluded from the stable
1451	// PreviewQueue surface).
1452	func (w *ExecuteBeadWorker) nextCandidate(ctx context.Context, results []ExecuteBeadReport, guards []work.Guard, labelFilter, targetBeadID string) (bead.Bead, []pickerSkip, bool, error) {
1453		// Use PreviewQueue for the stable filter+sort logic. Limit=0 returns all
1454		// entries so we can scan for the first candidate not already present in
1455		// the current drain results slice.
1456		entries, err := PreviewQueue(w.Store, PickerFilters{LabelFilter: labelFilter}, 0)
1457		if err != nil {
1458			return bead.Bead{}, nil, false, err
1459		}
1460	
1461		// Rebuild the ready list from the preview entries in picker order so we
1462		// can apply the per-run drain results slice on top. We need the original
1463		// bead values for the return; fetch them from ReadyExecution (already
1464		// ordered).
1465		ready, err := w.Store.ReadyExecution()
1466		if err != nil {
1467			return bead.Bead{}, nil, false, err
1468		}
1469		// Index by ID for O(1) lookup.
1470		byID := make(map[string]bead.Bead, len(ready))
1471		for _, b := range ready {
1472			byID[b.ID] = b
1473		}
1474		var skips []pickerSkip
1475		for _, entry := range entries {
1476			candidate, ok := byID[entry.BeadID]
1477			if !ok {
1478				// Should not happen; skip defensively.
1479				continue
1480			}
1481			if targetBeadID != "" && candidate.ID != targetBeadID {
1482				skips = append(skips, pickerSkip{BeadID: candidate.ID, Priority: candidate.Priority, BeadRank: queueRankPtr(candidate.Extra["queue-rank"]), Reason: "target_bead"})
1483				continue
1484			}
1485			if hasResultForBead(results, candidate.ID) {
1486				skips = append(skips, pickerSkip{BeadID: candidate.ID, Priority: candidate.Priority, BeadRank: queueRankPtr(candidate.Extra["queue-rank"]), Reason: "in_attempted"})
1487				continue
1488			}
1489			if entry.FilterDecision == FilterDecisionSkipped {
1490				// PreviewQueue already applied label_filter; record as skip.
1491				skips = append(skips, pickerSkip{BeadID: candidate.ID, Priority: candidate.Priority, BeadRank: queueRankPtr(candidate.Extra["queue-rank"]), Reason: "label_filter"})
1492				continue
1493			}
1494			allowed := true
1495			for _, guard := range guards {
1496				if guard == nil {
1497					continue
1498				}
1499				ok, reason := guard.Allow(ctx, candidate.ID)
1500				if ok {
1501					continue
1502				}
1503				allowed = false
1504				if reason != "" {
1505					skips = append(skips, pickerSkip{BeadID: candidate.ID, Priority: candidate.Priority, BeadRank: queueRankPtr(candidate.Extra["queue-rank"]), Reason: reason})
1506				}
1507				break
1508			}
1509			if !allowed {
1510				continue
1511			}
1512			return candidate, skips, true, nil
1513		}
1514		return bead.Bead{}, skips, false, nil
1515	}
