1764	// writeLoopEvent emits one structured JSONL line to sink describing a
1765	// milestone in an execute-bead loop run. Entries use the same envelope as
1766	// the Fizeau harness (session_id/seq/type/ts/data) so existing event
1767	// consumers can parse the stream uniformly. Errors are swallowed:
1768	// structured logging must never break the core execute-loop.
1769	func writeLoopEvent(sink io.Writer, sessionID, eventType string, data map[string]any, ts time.Time) {
1770		if sink == nil {
1771			return
1772		}
1773		if data == nil {
1774			data = map[string]any{}
1775		}
1776		entry := map[string]any{
1777			"session_id": sessionID,
1778			"type":       eventType,
1779			"ts":         ts.UTC().Format(time.RFC3339Nano),
1780			"data":       data,
1781		}
1782		line, err := json.Marshal(entry)
1783		if err != nil {
1784			return
1785		}
1786		_, _ = sink.Write(line)
1787		_, _ = sink.Write([]byte("\n"))
